import { useEffect, useState } from "react";
import api from "../api";

export default function Dashboard() {
  const [youth, setYouth] = useState([]);

  useEffect(() => {
    const fetchYouth = async () => {
      try {
        const res = await api.get("/");
        setYouth(res.data);
      } catch (err) {
        console.error(err.response?.data || err.message);
      }
    };
    fetchYouth();
  }, []);

  const total = youth.length;
  const checkedIn = youth.filter((y) => y.checkedIn).length;

  return (
    <div style={{ padding: "20px", fontFamily: "Arial, sans-serif" }}>
      <h1 style={{ textAlign: "center" }}>Church Event Management System</h1>

      <p>Total Registered: {total}</p>
      <p>Checked In: {checkedIn}</p>

      <h3>Recent Registrations</h3>
      {youth.slice(0, 5).map((y) => (
        <div key={y._id}>
          {y.fullName} - {y.congregation}
        </div>
      ))}

      <footer style={{ marginTop: "50px", textAlign: "center", fontSize: "12px" }}>
        Developed by Pianist Charles Wambua | Contact: 0745939344
      </footer>
    </div>
  );
}
